var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그러니까...... 유나가 던진 화염구에 맞고 나서 정신이 들었단 말이지?","JPN":"だから……ユナの火の玉に撃たれて気がついたってことね？","ENG":"So... You came to your senses after Yuna's fireball hit you?","TWN":"妳的意思是……妳被尤娜的火焰球擊中後就清醒了？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"으응. 그 전까지는 코스튬의 힘과 만족감에 취해서 아무 생각도 안 들었거든.","JPN":"う、うん。その前までは服の力と満足感のせいで何も考えられなかったの。","ENG":"Yeah. I was too drunk on the power of the costume to think of anything else until then.","TWN":"嗯，在那之前我沉醉於服裝的力量和成就感，沒辦法思考。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"그런데 유나가 던진 화염구에 한 대 맞으니까 정신이 확 돌아오더라고.","JPN":"だけどユナの火の玉を受けたら、はっと気が付いたの。","ENG":"But once Yuna's fireball smacked me, I got a grip on reality again.","TWN":"但是被尤娜的火焰球擊中之後，馬上就清醒了。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......뭐야, 그게? 인형의 주인이 직접 건 저주가 그렇게 쉽게 풀린다고?","JPN":"……なんだそれ？　人形の持ち主が直接かけた呪いがそんな簡単に解けただと？","ENG":"Seriously? That's how easy it is to lift the Puppet Master's curse?","TWN":"……什麼呀？木偶之主親自下的詛咒居然這麼容易就被破解了？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그러고보니 저번에 발푸르기스 성에서 인형을 상대할 때도 비슷한 일이 있긴 했어.","JPN":"そういえば、この前ヴァルプルギス城で人形を相手にしてた時も似たようなことがあったわね。","ENG":"Come to think of it, we saw something similar when we fought the puppets at Walpurgis Castle.","TWN":"對了，上次對付魔女之夜城木偶的時候也發生過類似的事情。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"유나의 화염구에 맞은 인형이 갑자기 실 끊어진 듯이 약해졌잖아.","JPN":"ユナの火の玉に撃たれた人形が、急に糸が切れたように弱くなったんでしょう？","ENG":"The puppets went all limp like a marionette with their strings cut when Yuna hit them with her fireballs.","TWN":"被尤娜的火焰球擊中的木偶，突然就像斷了線一樣變弱了。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그렇다면......","JPN":"そういうことか……","ENG":"You mean...","TWN":"這樣的話……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그래. 인형 실 태우기. 메이 할머니의 특기였잖아.","JPN":"そう。人形の糸燃やし。メイお婆ちゃんの特技だったわよね？","ENG":"Yup. Burning strings. That was Granny May's specialty.","TWN":"對了，梅伊奶奶最擅長燒毀木偶的線了。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"유나가 만들어 낸 불꽃에도 같은 힘이 있는 게 분명해.","JPN":"ユナが作り出した炎にも同じ力があるはずよ。","ENG":"Yuna's fireballs must have a similar power.","TWN":"尤娜的火焰應該擁有和奶奶相同的力量。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"인형의 실을 태워요......?","JPN":"人形の糸を燃やす……？","ENG":"Burning strings?","TWN":"焚燒木偶的線……？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"인형의 주인은 마법의 실로 인형들을 조종해.","JPN":"人形の持ち主は魔法の糸で人形を操る。","ENG":"The Puppet Master controls her puppets with her magic strings.","TWN":"木偶之主是通過魔法線操控木偶。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그게 끊어지면 인형들은 지배에서 풀려나지.","JPN":"その糸が切れたら人形たちは支配から解放される。","ENG":"Once the string is severed, she loses control over the puppets.","TWN":"如果線斷了，就無法操控木偶了。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"뭐야, 그냥 불 지르면 풀리는 저주였어? 별거 아니네.","JPN":"なんだ、ただ燃やせば解ける呪いだったの？　つまらない呪いだね。","ENG":"What? So all it took was a little fire? That sounds easy enough.","TWN":"什麼啊，原來放個火就能解開詛咒啊？也沒什麼了不起的。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"당연히 보통 마법으로는 어림도 없지. 바보야.","JPN":"普通の魔法じゃ到底できないんだ、バカ。","ENG":"Of course not, silly. Ordinary magic won't do the trick.","TWN":"普通魔法當然是不行的，妳這個傻瓜。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"실을 끊으려면 특별한 재능이 필요해. 이를테면 메이 할머니처럼.","JPN":"糸を切るには特別な才能が必要よ。メイお婆ちゃんのようにね｡","ENG":"It takes special talent to sever the strings. Like Granny May, for instance.","TWN":"要斷開線，就必須有特殊的能力，就好像梅伊奶奶一樣。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"하지만 할머니도 화염구 같은 초급 마법으로 실을 끊지는 못했는데......","JPN":"でもお婆ちゃんも火の玉のような初級魔法で糸を切ることはできなかったのに……","ENG":"But even Granny May couldn't do it with a basic spell like fireball...","TWN":"但即使是奶奶也無法用火焰球這種初級魔法燒毀線的……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"뭐, 잘은 모르겠지만 어쨌든 유나가 날 구해 줬단 소리지?","JPN":"まあよくわからないけど、とにかくユナが私を助けてくれたんだよね？","ENG":"Well, I don't know about the details, but you're saying that Yuna saved me, right?","TWN":"雖然我聽不太懂，但反正就是尤娜救了我對嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"그럼 조종당하는 다른 사람들도 구할 수 있겠네!","JPN":"じゃあ操られている他の人たちも助けられるかも！","ENG":"That means she could also save the other folks under control!","TWN":"那是不是也可以救其他被操控的人！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그래, 뭐...... 이론상으로는.","JPN":"そうだ。まあ……理論上は。","ENG":"Yeah... Theoretically.","TWN":"呃，當然……理論上是可以的。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"대단하다, 너! 처음 봤을 때부터 뭔가 해낼 줄 알고 있었다고!","JPN":"すごいよ、君！　初めて会った時から只者じゃないと思ったんだよ！","ENG":"That's amazing! I knew you were meant for greatness when I first saw you!","TWN":"妳好了不起啊！我第一次見到你的時候，就知道妳有本事！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그, 그랬어? 왠지 오자마자 구박 받았던 것 같은데......","JPN":"そ、そうですか？　来て早々怒られた気がするけど……","ENG":"Y-you did? I feel like you were busy yelling at me at first...","TWN":"是，是嗎？怪不得我剛來就欺負我……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"좋아! 당장 가자!","JPN":"よし！　今すぐ行こう！","ENG":"Alright! Let's get going then!","TWN":"很好！我們馬上去吧！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"감히 내가 만든 첫 할로윈 코스튬에 그딴 저주를 걸다니 용서 않겠어!","JPN":"私が作った初ハロウィン衣装にそんな呪いをかけたなんて……許さない！","ENG":"How dare she curse the very first Halloween costume I made? I'll never forgive her!","TWN":"竟敢在我做的第一個萬聖節服裝下那種詛咒，我絕不輕饒！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"마법소녀 네크로노미코를 보며 배운 매지컬 아이언 슈퍼슬램으로 본때를 보여 주지!","JPN":"魔法少女ネクロノミコで覚えた\\nマジカル・アイアン・スーパースラムで痛い目に合わせてやる！","ENG":"I'll kick her butt with the Magical Iron Superslam I learned watching Necronomiko the Girl Witch!","TWN":"我要用從魔法少女通靈美子中學到的超級魔幻鋼鐵大滿貫好好地教訓她！"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};